import React from 'react';

const ContactoPage = () => {
  const items = [
    {
      src: '/media/contactoPage/LP.png',
      alt: 'Universidad Católica Boliviana La Paz',
      text: 'Universidad Católica Boliviana\nLA PAZ',
      link: 'https://www.ucb.edu.bo/',
    },
    {
      src: '/media/contactoPage/SIS - H.png',
      alt: 'Carrera de Ingeniería de Sistemas',
      text: 'Carrera de Ingeniería\nde Sistemas',
      link: 'https://www.ucb.edu.bo/contacto',
    },
    {
      src: '/media/contactoPage/IIE - H.png',
      alt: 'Carrera de Ingeniería Innovación Empresarial',
      text: 'Carrera de Ingeniería\nInnovación empresarial',
      link: 'https://www.ucb.edu.bo/nosotros',
    },
  ];

  return (
    <main style={styles.page}>
      <header style={styles.header}>
        <div style={styles.line} />
        <h2 style={styles.subtitle}>EMPRESAS QUE FORJARON EL PAIS</h2>
        <div style={styles.line} />
      </header>

      <section style={styles.contentBox}>
        <h1 style={styles.title}>SEMANA DE ACTIVIDADES</h1>
        <p style={styles.description}>
          Explora las últimas noticias, actualizaciones y promociones disponibles en nuestra plataforma.
        </p>

        {/* Imágenes con texto y links */}
        <div style={styles.grid}>
          {items.map(({ src, alt, text, link }, idx) => (
            <a
              href={link}
              target="_blank"
              rel="noopener noreferrer"
              key={idx}
              style={styles.card}
            >
              <img src={src} alt={alt} style={styles.image} />
              <p style={styles.cardText}>
                {text.split('\n').map((line, i) => (
                  <React.Fragment key={i}>
                    {line}
                    <br />
                  </React.Fragment>
                ))}
              </p>
            </a>
          ))}
        </div>
      </section>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F5EEE2',
    minHeight: '100vh',
    padding: '4rem 2rem',
    fontFamily: "'Montserrat', sans-serif",
    color: '#032F27',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  header: {
    display: 'flex',
    alignItems: 'center',
    gap: '1rem',
    marginBottom: '2rem',
    width: '100%',
    maxWidth: 900,
    justifyContent: 'center',
  },
  line: {
    flex: 1,
    height: 3,
    backgroundImage:
      'repeating-linear-gradient(90deg, #032F27, #032F27 10px, transparent 10px, transparent 20px)',
    borderRadius: 2,
  },
  subtitle: {
    fontSize: '1rem',
    fontWeight: '600',
    letterSpacing: '0.35em',
    textTransform: 'uppercase',
    color: '#032F27',
    whiteSpace: 'nowrap',
  },
  contentBox: {
    backgroundColor: '#FDF8F0',
    padding: '3rem 4rem',
    borderRadius: '30px',
    boxShadow: '0 10px 20px rgba(3,47,39,0.1)',
    maxWidth: 900,
    textAlign: 'center',
  },
  title: {
    fontSize: '2.5rem',
    fontWeight: '700',
    marginBottom: '1.5rem',
  },
  description: {
    fontSize: '1.15rem',
    lineHeight: 1.6,
    maxWidth: 600,
    margin: '0 auto 3rem',
    color: '#032F27',
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(3, 1fr)',
    gap: '2rem',
    // Responsive grid:
    // Usa media query en React inline con un truco:
    // Pero mejor usar CSS o un hook; para simplicidad aquí:
    // Podemos usar 'auto-fit' con minmax para que se adapte:
    gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
  },
  card: {
    backgroundColor: '#F5EEE2',
    borderRadius: '20px',
    padding: '1.5rem',
    boxShadow: '0 4px 10px rgba(3,47,39,0.1)',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    textDecoration: 'none',
    cursor: 'pointer',
    userSelect: 'none',
    transition: 'transform 0.3s ease, box-shadow 0.3s ease',
    color: '#032F27',
  },
  image: {
    width: '120px',
    height: '120px',
    objectFit: 'contain',
    marginBottom: '1rem',
  },
  cardText: {
    fontSize: '1rem',
    fontWeight: '600',
    color: '#032F27',
    whiteSpace: 'pre-line',
  },
};

export default ContactoPage;
